module RefModule (  
    input wire clk,  
    input wire reset,  
    input wire signal_in,  
    output reg zero_cross_detected  
);  
    reg signal_prev;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset) begin  
            zero_cross_detected <= 0;  
            signal_prev <= 0;  
        end else begin  
            zero_cross_detected <= (signal_prev == 0 && signal_in == 1);  
            signal_prev <= signal_in;  
        end  
    end  
endmodule
